func TestEnumPermissionReplyRequestReply(t *testing.T) {
	t.Run("NewFromString_once", func(t *testing.T) {
		t.Parallel()
		val, err := NewPermissionReplyRequestReplyFromString("once")
		assert.NoError(t, err, "valid enum value should not return error")
		assert.Equal(t, PermissionReplyRequestReply("once"), val, "enum value should match expected wire value")
	})

	t.Run("NewFromString_always", func(t *testing.T) {
		t.Parallel()
		val, err := NewPermissionReplyRequestReplyFromString("always")
		assert.NoError(t, err, "valid enum value should not return error")
		assert.Equal(t, PermissionReplyRequestReply("always"), val, "enum value should match expected wire value")
	})

	t.Run("NewFromString_reject", func(t *testing.T) {
		t.Parallel()
		val, err := NewPermissionReplyRequestReplyFromString("reject")
		assert.NoError(t, err, "valid enum value should not return error")
		assert.Equal(t, PermissionReplyRequestReply("reject"), val, "enum value should match expected wire value")
	})

	t.Run("NewFromString_Invalid", func(t *testing.T) {
		_, err := NewPermissionReplyRequestReplyFromString("invalid_value_that_does_not_exist")
		assert.Error(t, err)
	})

	t.Run("Ptr", func(t *testing.T) {
		val, err := NewPermissionReplyRequestReplyFromString("once")
		assert.NoError(t, err)
		ptr := val.Ptr()
		assert.NotNil(t, ptr)
		assert.Equal(t, val, *ptr)
	})
}

